export function delegateEvent(selector,eventType,handler,container=document){const listener=(event)=>{const target=event.target.closest(selector);if(target&&container.contains(target)){handler.call(target,event,target);}};container.addEventListener(eventType,listener,{passive: false});return()=>container.removeEventListener(eventType,listener);}export function addEvents(element,events){const cleanup=[];Object.entries(events).forEach(([eventType,handler])=>{element.addEventListener(eventType,handler);cleanup.push(()=>element.removeEventListener(eventType,handler));});return()=>cleanup.forEach(fn=>fn());}export function triggerEvent(element,eventName,detail={}){const event=new CustomEvent(eventName,{bubbles: true,cancelable: true,detail});element.dispatchEvent(event);}export function stopEvent(event){event.preventDefault();event.stopPropagation();}